#include <coroutine>
#include <iostream>

struct Generator {
    struct promise_type {
        int current_value;
        Generator get_return_object() { return {}; }
        std::suspend_always initial_suspend() { return {}; }
        std::suspend_always final_suspend() noexcept { return {}; }
        void return_void() {}
        void unhandled_exception() {}
        std::suspend_always yield_value(int value) {
            current_value = value;
            return {};
        }
    };
};

// المُجمّع يبحث عن Generator::promise_type تلقائيًا
// هذا يعادل coroutine_traits<Generator>::promise_type
Generator my_coro() {
    co_yield 42;
    co_yield 100;
}

#include <coroutine>
#include <iostream>

// نوع إرجاع لا يملك promise_type بداخله
struct ExternalTask {
    int result;
};

// تخصيص coroutine_traits لأنواع إرجاع لا تتحكم فيها
namespace std {
template<>
struct coroutine_traits<ExternalTask> {
    struct promise_type {
        ExternalTask get_return_object() { return {}; }
        std::suspend_never initial_suspend() { return {}; }
        std::suspend_never final_suspend() noexcept { return {}; }
        void return_value(int value) {}
        void unhandled_exception() {}
    };
};
}

ExternalTask compute() {
    co_return 42;
}

