#include <coroutine>
#include <iostream>

struct Task {
    std::coroutine_handle<> handle = std::noop_coroutine();

    void resume() {
        handle.resume(); // آمن حتى لو لم يكن هناك coroutine حقيقي
    }

    ~Task() {
        if (!handle.done()) handle.destroy();
    }
};

int main() {
    Task t; // handle = noop_coroutine افتراضيًا
    t.resume(); // لا يفعل شيئًا — لا يرمي خطأ
    std::cout << "آمن" << '\n';
}

#include <coroutine>
#include <iostream>

void process(std::coroutine_handle<> h) {
    // بدون noop_coroutine: يجب الفحص
    // if (h) h.resume();

    // مع noop_coroutine كافتراضي: لا حاجة للفحص
    h.resume(); // دائمًا آمن
}

int main() {
    // بدل تمرير nullptr عند عدم وجود coroutine
    process(std::noop_coroutine()); // آمن
    std::cout << "تم" << '\n';
}
